sys_script_include.script:
var CandidateDetails = Class.create();

CandidateDetails.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getCandidateData: function() {

        var candidateId = this.getParameter('sysparm_candidate');

        var gr = new GlideRecord('x_2053278_ai_res_0_candidatee');

        if (gr.get(candidateId)) {

            var obj = {};

            obj.name = gr.candidate_name.toString();
            obj.job_title = gr.applied_job.getDisplayValue();
            obj.resume_score = gr.resume_score.toString();
            obj.skill_match = gr.skill_match.toString();
            obj.status = gr.status.toString();
            obj.ai_recommendation = gr.ai_recommendation.toString();
            obj.interview_date = gr.interview_date.toString();
            obj.ai_feedback = gr.ai_feedback.toString();

            return JSON.stringify(obj);
        }

        return "{}";
    },

    type: 'CandidateDetails'
});
